parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "text": { "type": "string", "description": "Plain text fallback for push notifications and accessibility." },
    "blocks": {
      "type": "array",
      "items": {
        "oneOf": [
          { "type": "object", "properties": { "type": { "const": "header" }, "text": { "type": "object", "properties": { "type": { "const": "plain_text" }, "text": { "type": "string" } }, "required": ["type", "text"] } }, "required": ["type", "text"] },
          { "type": "object", "properties": { "type": { "const": "section" }, "text": { "type": "object", "properties": { "type": { "const": "mrkdwn" }, "text": { "type": "string" } }, "required": ["type", "text"] } }, "required": ["type", "text"] },
          { "type": "object", "properties": { "type": { "const": "divider" } }, "required": ["type"] },
          { "type": "object", "properties": { "type": { "const": "context" }, "elements": { "type": "array", "items": { "type": "object", "properties": { "type": { "const": "mrkdwn" }, "text": { "type": "string" } }, "required": ["type", "text"] } } }, "required": ["type", "elements"] }
        ]
      }
    }
  },
  "required": ["text", "blocks"]
}
